@@ -0,0 +1,124 @@
+{
+  "$schema": "https://json-schema.org/draft/2020-12/schema",
+  "$id": "https://process-triage.dev/schemas/report-config/1.0.0",
+  "title": "Process Triage Report Configuration",
+  "description": "Schema for HTML report generation options",
+  "type": "object",
+  "additionalProperties": false,
+  "properties": {
+    "schema_version": {
+      "type": "string",
+      "const": "1.0.0"
+    },
+    "title": {
+      "type": "string",
+      "description": "Custom report title (defaults to session ID)"
+    },
+    "theme": {
+      "type": "string",
+      "enum": ["light", "dark", "auto"],
+      "default": "auto",
+      "description": "Color theme for the report"
+    },
+    "embed_assets": {
+      "type": "boolean",
+      "default": false,
+      "description": "Inline CDN assets for offline viewing"
+    },
+    "galaxy_brain": {
+      "type": "boolean",
+      "default": false,
+      "description": "Include galaxy-brain math transparency tab"
+    },
+    "sections": {
+      "type": "object",
+      "description": "Control which sections are included",
+      "additionalProperties": false,
+      "properties": {
+        "overview": { "type": "boolean", "default": true },
+        "candidates": { "type": "boolean", "default": true },
+        "evidence": { "type": "boolean", "default": true },
+        "actions": { "type": "boolean", "default": true },
+        "telemetry": { "type": "boolean", "default": true },
+        "galaxy_brain": { "type": "boolean", "default": false }
+      }
+    },
+    "cdn_config": {
+      "type": "object",
+      "description": "CDN library configuration",
+      "additionalProperties": false,
+      "properties": {
+        "base_url": {
+          "type": "string",
+          "default": "https://cdn.jsdelivr.net/npm",
+          "description": "CDN base URL for library loading"
+        },
+        "fallback_enabled": {
+          "type": "boolean",
+          "default": true,
+          "description": "Enable fallback rendering if CDN fails"
+        },
+        "libraries": {
+          "type": "object",
+          "description": "Library version pins with SRI hashes",
+          "additionalProperties": {
+            "$ref": "#/$defs/cdn_library"
+          }
+        }
+      }
+    },
+    "limits": {
+      "type": "object",
+      "description": "Resource limits for report generation",
+      "additionalProperties": false,
+      "properties": {
+        "max_candidates": {
+          "type": "integer",
+          "minimum": 1,
+          "default": 1000,
+          "description": "Max candidates to include in table"
+        },
+        "max_timeline_points": {
+          "type": "integer",
+          "minimum": 100,
+          "default": 10000,
+          "description": "Max data points for timeline charts"
+        },
+        "embed_size_limit_mb": {
+          "type": "number",
+          "minimum": 1,
+          "default": 10,
+          "description": "Max size for embedded assets (MB)"
+        }
+      }
+    },
+    "redaction_profile": {
+      "type": "string",
+      "enum": ["minimal", "safe", "forensic"],
+      "default": "safe",
+      "description": "Redaction level for displayed data"
+    }
+  },
+  "$defs": {
+    "cdn_library": {
+      "type": "object",
+      "required": ["version", "sri"],
+      "additionalProperties": false,
+      "properties": {
+        "version": {
+          "type": "string",
+          "description": "Pinned version number"
+        },
+        "sri": {
+          "type": "string",
+          "pattern": "^sha384-[A-Za-z0-9+/=]+$",
+          "description": "Subresource integrity hash (SHA-384)"
+        },
+        "path": {
+          "type": "string",
+          "description": "Path within npm package"
+        }
+      }
+    }
+  }
+}
